const cfg = $input.first().json;

const projects = [
  { key: 'inbox', id: cfg.VIKUNJA_PROJECT_INBOX_ID },
  { key: 'termine', id: cfg.VIKUNJA_PROJECT_TERMINE_ID },
  { key: 'menschen', id: cfg.VIKUNJA_PROJECT_MENSCHEN_ID },
  { key: 'haushalt', id: cfg.VIKUNJA_PROJECT_HAUSHALT_ID },
  { key: 'putzen', id: cfg.VIKUNJA_PROJECT_PUTZEN_ID },
  { key: 'einkaufen', id: cfg.VIKUNJA_PROJECT_EINKAUFEN_ID },
  { key: 'sport', id: cfg.VIKUNJA_PROJECT_SPORT_ID },
  { key: 'finanzen', id: cfg.VIKUNJA_PROJECT_FINANZEN_ID },
  { key: 'papierkram', id: cfg.VIKUNJA_PROJECT_PAPIERKRAM_ID },
  { key: 'digital', id: cfg.VIKUNJA_PROJECT_DIGITAL_ID },
  { key: 'auto', id: cfg.VIKUNJA_PROJECT_AUTO_ID },
  { key: 'sicherheit', id: cfg.VIKUNJA_PROJECT_SICHERHEIT_ID },
];

const validProjects = projects
  .map(p => ({
    key: p.key,
    project_id: Number(p.id),
  }))
  .filter(p => Number.isFinite(p.project_id) && p.project_id > 0);

if (validProjects.length === 0) {
  return [
    {
      json: {
        status: 'FEHLER',
        message: 'Keine gültigen Vikunja-Projekt-IDs gefunden.',
        input: cfg,
      },
    },
  ];
}

return validProjects.map(p => ({
  json: p,
}));

const items = $input.all();

const today = new Date();

const dateString = today.toLocaleDateString('de-DE', {
  weekday: 'long',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
});

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function pickTaskName(task) {
  return clean(
    task.title ??
    task.name ??
    task.text ??
    task.task ??
    task.content ??
    task.summary ??
    'Unbenannte Aufgabe'
  );
}

function pickProject(task) {
  return clean(
    task.project_title ??
    task.project_name ??
    task.project ??
    task.namespace_name ??
    task.bucket_title ??
    task.key ??
    'Ohne Projekt'
  );
}

function pickDueDate(task) {
  return clean(
    task.due_date ??
    task.dueDate ??
    task.due ??
    task.due_at ??
    ''
  );
}

function pickPriority(task) {
  return clean(
    task.priority ??
    task.prio ??
    ''
  );
}

// Diese Begriffe werden aus dem Tagesplan entfernt.
// Ziel: Nur echte Aufgaben anzeigen, keine Checks / Routinen / Meta-Aufgaben.
const ignoreWords = [
  'kalender',
  'termin',
  'termine prüfen',
  'kalender prüfen',
  'kalender für heute prüfen',
  'kalender für morgen prüfen',
  'heute prüfen',
  'morgen prüfen',

  'tagesplan',
  'tagesplan prüfen',
  'daily',
  'daily check',
  'daily-check',
  'wochenplan',
  'wochenreview',
  'review',

  'abend check',
  'abend-check',
  'abendroutine',
  'abend routine',

  'backup',
  'backup status',
  'backup-status',
  'backup prüfen',
  'backup check',
  'backup-check',

  'check machen',
  'prüfen',
  'kontrollieren',
  'status prüfen',

  'reset',
  'wohnungs-reset',
  'wohnung reset',
  'kurz resetten',

  'kurz saugen',
  'bad kurz',
  'dusche/badewanne',
];

// Optional: Projekte/Bereiche ignorieren, falls dort nur Routinen liegen.
// Wenn du nichts nach Projekt filtern willst, leer lassen.
const ignoredProjects = [
  // Beispiel:
  // 'termine',
];

const tasks = items
  .map(item => item.json)
  .filter(task => {
    const done =
      task.done === true ||
      task.is_done === true ||
      task.completed === true ||
      task.status === 'done';

    if (done) return false;

    const title = pickTaskName(task).toLowerCase();
    const project = pickProject(task).toLowerCase();

    const isIgnoredByTitle = ignoreWords.some(word =>
      title.includes(word.toLowerCase())
    );

    const isIgnoredByProject = ignoredProjects.some(projectName =>
      project.includes(projectName.toLowerCase())
    );

    if (isIgnoredByTitle || isIgnoredByProject) return false;

    return true;
  })
  .map(task => ({
    title: pickTaskName(task),
    project: pickProject(task),
    due: pickDueDate(task),
    priority: pickPriority(task),
  }))
  .filter(task => task.title && task.title !== 'Unbenannte Aufgabe');

const taskLines = tasks.map((task, index) => {
  const parts = [
    `${index + 1}. ${task.title}`,
    task.project ? `Bereich: ${task.project}` : '',
    task.due ? `Fällig: ${task.due}` : '',
    task.priority ? `Priorität: ${task.priority}` : '',
  ].filter(Boolean);

  return parts.join(' | ');
});

const prompt = `
Du bist mein persönlicher Tagesplan-Assistent.

Erstelle für Dennis einen kurzen, motivierenden Tagesplan für heute: ${dateString}.

Wichtig:
- Nimm nur echte Aufgaben aus Vikunja.
- Keine Meta-Aufgaben nennen.
- Keine Routine-Checks nennen.
- Kalender prüfen, Termine prüfen, Tagesplan prüfen, Abend-Check, Backup-Check, Reviews, Reset-Aufgaben und reine Prüfaufgaben ignorieren.
- Keine Aufgaben erfinden.
- Maximal 5 Hauptaufgaben.
- Harte oder wichtige Aufgaben zuerst.
- Telegram-tauglich, kurz und motivierend.
- Wenn keine echten Aufgaben übrig bleiben, schreibe freundlich, dass heute keine echten Aufgaben offen sind.
- Schreibe nicht, dass du Aufgaben ignoriert hast.

Echte offene Aufgaben aus Vikunja:
${taskLines.length > 0 ? taskLines.join('\n') : 'Keine echten offenen Aufgaben gefunden.'}

Ausgabeformat:
Guten Morgen Dennis! 👋

Heute zählen vor allem diese Aufgaben:

1. ...
2. ...
3. ...
4. ...
5. ...

Kurzer motivierender Abschlusssatz.
`;

return [
  {
    json: {
      task_count: tasks.length,
      prompt,
      debug_tasks: tasks.slice(0, 30),
      filtered_out_note: 'Meta-Aufgaben wie Kalender prüfen, Tagesplan prüfen, Abend-Check, Backup-Check und reine Prüfaufgaben wurden entfernt.',
    },
  },
];

const text =
  $json.output?.[0]?.content?.[0]?.text
  ?? $json.output?.[0]?.text
  ?? $json.content?.[0]?.text
  ?? $json.text
  ?? 'Guten Morgen. Heute gibt es keinen Tagesplan.';

return [
  {
    json: {
      text,
      telegram_text: text,
    },
  },
];

