if (validProjects.length === 0) {
  return [
    {
      json: {
        status: 'FEHLER',
        message: 'Keine gültigen Vikunja-Projekt-IDs gefunden.',
        input: cfg,
      },
    },
  ];
}

return validProjects.map(p => ({
  json: p,
}));

const allItems = $input.all().map(i => i.json);
const now = new Date();
const today = now.toISOString().slice(0,10);

const todays = allItems
  .filter(t => !t.done)
  .filter(t => !t.due_date || (t.due_date || '').slice(0,10) <= today)
  .sort((a,b) => (b.priority || 0) - (a.priority || 0))
  .slice(0,40)
  .map(t => ({
    id: t.id,
    title: t.title,
    due_date: t.due_date,
    priority: t.priority,
    description: t.description
  }));

return [{
  json: {
    prompt: `Erstelle einen kurzen Abend-Review für Dennis per Telegram. Keine Vorwürfe. Teile in: noch offen/Vorschlag. Wenn weiche Aufgaben offen sind, schlage Verschiebung vor. Harte Aufgaben klar markieren. Offene Aufgaben: ${JSON.stringify(todays)}`
  }
}];

