const now = new Date();

function dateKeyBerlin(dateValue) {
  if (!dateValue) return '';

  const d = new Date(dateValue);
  if (Number.isNaN(d.getTime())) return '';

  return new Intl.DateTimeFormat('en-CA', {
    timeZone: 'Europe/Berlin',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).format(d);
}

const todayKey = dateKeyBerlin(now);

function isTodayBerlin(dateValue) {
  return dateKeyBerlin(dateValue) === todayKey;
}

function isStravaActivity(i) {
  return (
    i.source === 'strava' ||
    i.sport_type !== undefined ||
    i.start_date_local !== undefined ||
    i.start_date !== undefined && i.athlete !== undefined
  );
}

function isVikunjaTask(i) {
  return (
    i.source === 'vikunja' ||
    i.title !== undefined ||
    i.done !== undefined ||
    i.due_date !== undefined
  );
}

function getTaskTitle(i) {
  return String(
    i.title ??
    i.name ??
    i.text ??
    ''
  );
}

function isDone(i) {
  return (
    i.done === true ||
    i.is_done === true ||
    i.completed === true ||
    i.status === 'done'
  );
}

// Strava-Aktivitäten heute
const stravaActivitiesToday = items.filter(i => {
  if (!isStravaActivity(i)) return false;

  const activityDate =
    i.start_date_local ??
    i.start_date ??
    i.raw?.start_date_local ??
    i.raw?.start_date;

  return isTodayBerlin(activityDate);
});

// Hevy optional, falls später vorhanden
const hevyActivitiesToday = items.filter(i => {
  const source = String(i.source ?? '').toLowerCase();
  if (!source.includes('hevy')) return false;

  const date =
    i.start_time ??
    i.startTime ??
    i.created_at ??
    i.date ??
    i.raw?.start_time ??
    i.raw?.created_at;

  return isTodayBerlin(date);
});

// Offene Sportaufgaben aus Vikunja
const sportTasks = items.filter(i => {
  if (!isVikunjaTask(i)) return false;
  if (isDone(i)) return false;

  const title = getTaskTitle(i).toLowerCase();

  return /sport|gym|training|workout|laufen|joggen|run|fitness|hevy|strava/.test(title);
});

const workoutCountToday = stravaActivitiesToday.length + hevyActivitiesToday.length;

const stravaSummary = stravaActivitiesToday.map(a => ({
  id: a.id,
  name: a.name,
  type: a.sport_type ?? a.type,
  start: a.start_date_local ?? a.start_date,
  moving_time: a.moving_time,
  distance: a.distance,
}));

if (workoutCountToday === 0) {
  return [
    {
      json: {
        action: 'notify',
        workout_count_today: 0,
        strava_count_today: 0,
        hevy_count_today: 0,
        open_sport_tasks: sportTasks.length,
        message:
          `🏃 Sport-Status heute\n\n` +
          `Strava/Laufen/Cardio: 0\n` +
          `Hevy/Gym/Home: 0\n\n` +
          `Noch offen: ${sportTasks.length} Workout(s).\n` +
          `Wenn heute nichts mehr geht: Sportaufgabe im Abend-Review verschieben.`,
      },
    },
  ];
}

if (sportTasks.length === 0) {
  return [
    {
      json: {
        action: 'notify',
        workout_count_today: workoutCountToday,
        strava_count_today: stravaActivitiesToday.length,
        hevy_count_today: hevyActivitiesToday.length,
        activities: stravaSummary,
        message:
          `✅ Sport erkannt!\n\n` +
          `Heute wurden ${workoutCountToday} Workout(s) erkannt.\n` +
          `Strava: ${stravaActivitiesToday.length}\n` +
          `Hevy: ${hevyActivitiesToday.length}\n\n` +
          `Es gibt aber keine passende offene Vikunja-Sportaufgabe zum Abhaken.`,
      },
    },
  ];
}

// Erste passende offene Sportaufgabe abhaken
const task = sportTasks[0];
const activity = stravaActivitiesToday[0] ?? hevyActivitiesToday[0];

return [
  {
    json: {
      action: 'complete_task',
      task_id: task.id,
      task_title: getTaskTitle(task),
      workout_count_today: workoutCountToday,
      strava_count_today: stravaActivitiesToday.length,
      hevy_count_today: hevyActivitiesToday.length,
      activity_name: activity?.name ?? activity?.title ?? 'Workout',
      activity_type: activity?.sport_type ?? activity?.type ?? 'Workout',
      activity_start: activity?.start_date_local ?? activity?.start_date ?? '',
      message:
        `✅ Sport erkannt und Aufgabe wird abgehakt.\n\n` +
        `Aktivität: ${activity?.name ?? activity?.title ?? 'Workout'}\n` +
        `Aufgabe: ${getTaskTitle(task)}`,
